












  '["每次引入一种新食材，连续观察3天，确认无过敏或消化不适再添加下一种","质地以细腻泥糊为主，可用勺子轻压即化","辅食时间安排在哺乳后或两次哺乳之间，初期每日1次即可","铁是6个月后最关键的营养素，优先选择高铁米粉或动物性铁源"]',
  '[{"q":"宝宝不愿意张嘴怎么办？","a":"用小勺轻触嘴唇外侧，等待宝宝主动张嘴，不要强行喂入。初期接受度低属正常，连续尝试10-15天。"},{"q":"辅食后大便颜色变深/变绿正常吗？","a":"正常现象，是食物色素（如南瓜、菠菜）作用，无需担心。若出现稀水便超过3次或带血应就医。"},{"q":"需要每天吃辅食吗？","a":"初期建议每天1次，让宝宝逐渐适应。出现不适时可暂停1-2天再尝试。"}]',
  '[{"time":"08:30","title":"晨间哺乳","description":"母乳或配方奶，维持主营养来源"},{"time":"10:00","title":"辅食尝试","description":"高铁米粉或蔬菜泥，初期1-2勺，逐步增加"},{"time":"12:00","title":"午间哺乳","description":"母乳或配方奶"},{"time":"15:00","title":"下午哺乳","description":"母乳或配方奶"},{"time":"18:00","title":"傍晚哺乳","description":"母乳或配方奶，晚间不建议添加辅食"}]',
  1),
('guide-002', '8-9', '8-9月', '8-9个月：细颗粒咀嚼期', '逐步从泥糊过渡到带细小颗粒的碎末状，引导宝宝用牙龈咀嚼。每日辅食增至2次，可开始少量尝试手抓食。',
  '["质地从泥糊升级为碎末状，可保留少量小颗粒锻炼咀嚼","每日辅食次数增至2次，搭配2-3次母乳/配方奶","开始引入软质手抓食（如软苹果条、蒸熟的胡萝卜条），锻炼精细运动","鸡蛋从蛋黄开始引入，确认无过敏后再尝试全蛋"]',
  '[{"q":"宝宝还是不会咀嚼，一直吞咽怎么办？","a":"减小食物颗粒度，让宝宝先习惯口感。尝试把软食放在臼齿位置（牙床侧面），引导咀嚼动作。不要因为担心噎食而一直喂泥糊，适当颗粒感是咀嚼发展必要刺激。"},{"q":"宝宝开始用手抓碗里的食物，要阻止吗？","a":"不要阻止！手抓食是宝宝探索和自主进食的重要方式，保持卫生即可，可以准备手抓食专区。"},{"q":"引入蛋白质后大便发臭是正常的吗？","a":"正常现象。引入肉类和蛋白质后大便气味会变化，只要大便成形、宝宝状态良好即无需担心。"}]',
  '[{"time":"08:00","title":"早餐辅食","description":"碎末状主食（小米粥、烂面）+ 蔬菜碎末"},{"time":"10:00","title":"上午哺乳","description":"母乳或配方奶200ml"},{"time":"12:00","title":"午餐辅食","description":"蛋白质（鸡肉末/鱼肉末）+ 蔬菜 + 少量主食"},{"time":"15:00","title":"下午哺乳+水果","description":"母乳或配方奶 + 软质水果泥少量"},{"time":"18:00","title":"晚间哺乳","description":"母乳或配方奶，晚间辅食量少于白天"}]',
  2),
('guide-003', '10-12', '10-12月', '10-12个月：软烂固体进阶期', '食物质地接近软烂固体，可提供更丰富的主食形式。每日三餐节律初步建立，手抓食比例增加，自主进食意愿增强。',
  '["质地升级为软烂块状，手指可轻松压碎即可","每日三餐+1-2次加餐节律初步建立，规律进食时间","手抓食占比增加：蒸糕、馒头小块、软煮蔬菜段都适合","食物种类基本覆盖六大类，但仍需无盐或极低盐"]',
  '[{"q":"宝宝开始挑食，只吃某几样东西怎么办？","a":"保持食物多样性，用已接受的食物带出新食物（如米饭混入少量新蔬菜）。不要强迫，也不要因拒绝就彻底放弃某种食物，一般需要尝试10-15次宝宝才会接受。"},{"q":"可以加盐了吗？","a":"不建议。1岁前肾脏功能发育未成熟，食物天然钠含量已足够。1岁后可极少量添加，每日盐摄入应低于1克。"},{"q":"宝宝到了饭点还要吃奶，怎么断奶过渡？","a":"可先保留早晚两次哺乳，三餐逐步以固体食物为主。断奶不必急于一时，顺应宝宝节奏更重要。"}]',
  '[{"time":"07:30","title":"早餐","description":"软饭或粥 + 蛋羹/肉末 + 蔬菜"},{"time":"10:00","title":"上午加餐","description":"水果块或软质手抓食小点心"},{"time":"12:00","title":"午餐","description":"主食 + 蛋白质 + 蔬菜，可尝试和家人同桌"},{"time":"15:00","title":"下午加餐","description":"母乳/配方奶 + 手抓小食"},{"time":"18:00","title":"晚餐","description":"以易消化食物为主，不宜过饱"}]',
  3),
('guide-004', '12-18', '12-18月', '12-18个月：三餐规律建立期', '逐步断奶过渡，建立一日三餐加两次点心的节律。食物种类与大人同桌，但需单独调味（无盐或极低盐），重点培养自主进食能力。',
  '["一日三餐加两次点心节律稳固，减少哺乳次数","允许少量盐（每日<1克），避免酱油、鸡精等加工调味品","鼓励自主进食，提供适合手抓的食物形状，允许''脏乱''","若出现明显挑食，先排除生病或出牙期影响，再考虑进食行为引导"]',
  '[{"q":"宝宝开始扔碗、玩食物，要制止吗？","a":"适度允许宝宝探索食物，这是感官发展的正常过程。可设定进食区域和时间，超过30分钟无进食意愿则撤掉，不要边玩边喂或边看电视边喂。"},{"q":"宝宝突然不爱吃饭了，是挑食还是厌食期？","a":"12-18月龄宝宝生长速度放缓，食欲自然下降，属正常生理现象。保持规律进餐时间，不强迫，不追喂，出牙期也会影响食欲。"},{"q":"需要额外补充维生素D和钙吗？","a":"若户外活动不足，建议继续补充维生素D（400IU/天）。饮食中奶制品（酸奶、奶酪）和绿叶蔬菜可补充钙，一般无需额外补钙。"}]',
  '[{"time":"07:30","title":"早餐","description":"杂粮粥/面条/馒头 + 蛋类 + 蔬菜"},{"time":"10:00","title":"上午点心","description":"水果、酸奶或全麦小饼干"},{"time":"12:00","title":"午餐","description":"软饭 + 荤素搭配，尝试同桌进食"},{"time":"15:00","title":"下午点心","description":"水果或少量坚果碎拌入酸奶"},{"time":"18:30","title":"晚餐","description":"主食 + 蔬菜 + 蛋白质，清淡易消化"}]',
  4),
('guide-005', '18-24', '18-24月', '18-24个月：食物多样性培养期', '饮食接近成人，重点培养不挑食习惯，丰富食物色彩与口味多样性。继续控盐少油，鼓励宝宝参与简单备餐环节增加进食兴趣。',
  '["每日食物争取覆盖5种颜色，培养多样性饮食习惯","盐每日<2克，仍需低于成人标准，避免加工食品","可尝试用宝宝安全餐具自主进食，允许进食节奏慢","睡前1小时避免高糖高脂食物，建立良好进食与睡眠节律"]',
  '[{"q":"宝宝特别爱吃甜食零食，怎么控制？","a":"不完全禁止但严格限量，将零食安排在固定点心时间（每日1-2次），用天然甜食替代（水果、低糖酸奶）。避免用甜食作为奖励或安慰，以免建立情绪性进食模式。"},{"q":"偏食非常严重，几乎不吃蔬菜怎么办？","a":"尝试将蔬菜藏入主食（菜肉包、菜饺）、改变烹饪方式（蒸/烤更香），让宝宝参与洗菜/择菜过程增加熟悉感。坚持提供，不强迫，大多数宝宝随年龄增长会改善。"},{"q":"宝宝可以喝鲜奶了吗？","a":"2岁后可以喝全脂鲜奶，每日建议量350-500ml。但鲜奶不能替代正餐，应作为点心或加餐的一部分。"}]',
  '[{"time":"07:30","title":"早餐","description":"杂粮主食 + 蛋类或豆制品 + 蔬菜"},{"time":"10:00","title":"上午点心","description":"当季水果 + 少量坚果碎"},{"time":"12:00","title":"午餐","description":"五颜六色搭配，荤素比例约1:2"},{"time":"15:00","title":"下午点心","description":"低糖酸奶或全麦面包片"},{"time":"18:30","title":"晚餐","description":"清淡为主，适当减少主食比例避免积食"}]',
  5);

