('guide-rule-010', 'guide-004', 'recommended', '推荐添加', '["杂粮软饭","蒸蛋","清蒸鱼","豆腐脑","少油清炒蔬菜","酸奶","全麦面包","各类瓜果","牛肉丸","虾仁"]'),
('guide-rule-011', 'guide-004', 'cautious', '谨慎尝试', '["坚果碎（混入食物中）","生冷水果（少量）","花生酱（薄涂）","低辣食物"]'),
