INSERT INTO symptom_food_rules (id, symptom_guide_id, type, food, reason) VALUES
('symptom-rule-001', 'symptom-001', 'avoid', '高油脂食物', '会增加肠胃负担。'),
('symptom-rule-002', 'symptom-001', 'recommended', '焦米粥', '更温和，利于恢复。'),
